import json
import pymysql
from aws_lambda_powertools import Tracer, Logger

tracer = Tracer()
logger = Logger()

def lambda_handler(event, context):
    # Get search parameters from API Gateway event
    params = event["queryStringParameters"]
    
    # Build SQL query dynamically based on search parameters
    sql = "SELECT * FROM products WHERE"
    for key in params:
        if key == "name":
            sql += f" name LIKE '%{params[key]}%'"
        elif key == "price":
            sql += f" price >= {params[key]}"
    
    # Connect to RDS MySQL database using pymysql
    conn = pymysql.connect(host="your-rds-instance-endpoint", user="your-username", password="your-password", db="your-database")
    cursor = conn.cursor()
    
    # Execute SQL query and fetch results
    cursor.execute(sql)
    results = cursor.fetchall()
    
    # Close database connection
    cursor.close()
    conn.close()
    
    # Return search results as JSON response
    return {
        "statusCode": 200,
        "body": json.dumps(results)
    }